!function(){"use strict";if("IntersectionObserver"in window){const e=new IntersectionObserver((e,t)=>{e.forEach(e=>{if(e.isIntersecting){const a=e.target;a.dataset.src&&(a.src=a.dataset.src,a.removeAttribute("data-src")),a.dataset.srcset&&(a.srcset=a.dataset.srcset,a.removeAttribute("data-srcset")),a.classList.add("lazy-loaded"),t.unobserve(a)}})},{root:null,rootMargin:"50px",threshold:.01});document.querySelectorAll('img[data-src], img[loading="lazy"]').forEach(t=>e.observe(t))}else{document.querySelectorAll("img[data-src]").forEach(e=>{e.dataset.src&&(e.src=e.dataset.src,e.removeAttribute("data-src")),e.dataset.srcset&&(e.srcset=e.dataset.srcset,e.removeAttribute("data-srcset"))})}const e=document.createElement("style");e.textContent='\n        img[loading="lazy"]:not(.lazy-loaded) {\n            background: linear-gradient(90deg, #f0f0f0 25%, #e0e0e0 50%, #f0f0f0 75%);\n            background-size: 200% 100%;\n            animation: loading 1.5s ease-in-out infinite;\n        }\n        \n        @keyframes loading {\n            0% { background-position: 200% 0; }\n            100% { background-position: -200% 0; }\n        }\n        \n        img.lazy-loaded {\n            animation: fadeIn 0.3s ease-in;\n        }\n        \n        @keyframes fadeIn {\n            from { opacity: 0; }\n            to { opacity: 1; }\n        }\n    ',document.head.appendChild(e)}();